"""Balkan.works consumer shell: calm finance UI, large local discovery cards."""

from __future__ import annotations


def render_superapp_page(language: str = "SR", initial_tab: str = "home", initial_module: str = "") -> str:
    language = language if language in {"SR", "HR", "BS", "MK", "EN", "DE"} else "SR"
    tab = initial_tab if initial_tab in {"home", "explore", "rewards", "inbox", "profile"} else "home"
    return r'''<!doctype html><html lang="__LANG__"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1,viewport-fit=cover"><title>Balkan.works</title><style>
:root{--ink:#082b25;--pine:#0d4036;--paper:#f6f7f3;--card:#fff;--orange:#ff6c37;--mint:#e4f3e9;--line:#dce4de;--muted:#62746e;--shadow:0 20px 45px #092c2610}*{box-sizing:border-box}body{margin:0;background:var(--paper);font:15px Inter,ui-sans-serif,system-ui,-apple-system,sans-serif;color:var(--ink)}button,input{font:inherit}.shell{max-width:1440px;margin:auto;padding:0 40px 110px}.top{height:84px;display:grid;grid-template-columns:auto minmax(300px,620px) auto;gap:28px;align-items:center}.brand{font-weight:950;letter-spacing:-1.2px;font-size:25px;text-decoration:none;color:var(--ink)}.brand i{color:var(--orange);font-style:normal}.global-search{height:47px;border:1px solid var(--line);background:#fff;border-radius:14px;display:flex;align-items:center;gap:10px;padding:5px 6px 5px 15px;box-shadow:0 7px 20px #092c2606}.global-search span{color:var(--muted);font-size:19px}.global-search input{border:0;outline:0;min-width:0;flex:1;color:var(--ink)}.global-search button{border:0;background:var(--pine);color:#fff;border-radius:10px;height:35px;padding:0 14px;font-weight:800}.location{border:1px solid var(--line);background:#fff;border-radius:12px;padding:10px 12px;color:var(--pine);font-weight:800;font-size:13px;white-space:nowrap}.view{display:none}.view.active{display:block}.hero{min-height:302px;position:relative;overflow:hidden;border-radius:26px;padding:46px;background:linear-gradient(120deg,#0a342c,#165b4a);color:#fff;display:flex;flex-direction:column;justify-content:center}.hero:after{content:'';position:absolute;width:430px;height:430px;right:-80px;top:-145px;border:58px solid #b8eea71c;border-radius:50%}.eyebrow{position:relative;z-index:1;color:var(--orange);font-size:11px;letter-spacing:1.5px;font-weight:900;text-transform:uppercase}.hero h1{position:relative;z-index:1;margin:13px 0 10px;font:clamp(39px,5vw,66px)/.95 Georgia,serif;letter-spacing:-2.6px;max-width:720px}.hero p{position:relative;z-index:1;max-width:610px;color:#d5e5dd;line-height:1.55;margin:0}.hero-actions{display:flex;gap:10px;margin-top:24px;position:relative;z-index:1}.hero-actions button{border:0;border-radius:11px;padding:12px 15px;font-weight:850}.primary{background:var(--orange);color:#fff}.soft{background:#ffffff19;color:#fff;border:1px solid #ffffff2d!important}.section{margin-top:38px}.section-head{display:flex;justify-content:space-between;align-items:end;margin-bottom:14px;gap:12px}.section-head h2{margin:5px 0 0;font:31px Georgia,serif;letter-spacing:-1.1px}.section-head button{border:0;background:none;color:var(--orange);font-weight:850}.feature-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:15px}.feature{position:relative;isolation:isolate;min-height:262px;border-radius:19px;overflow:hidden;color:#fff;text-decoration:none;padding:19px;display:flex;flex-direction:column;justify-content:end;background:#193f36;box-shadow:var(--shadow);transition:transform .18s}.feature:hover{transform:translateY(-4px)}.feature:before{content:'';position:absolute;z-index:-2;inset:0;background:center/cover no-repeat}.feature:after{content:'';position:absolute;z-index:-1;inset:0;background:linear-gradient(0deg,#062d25df 0%,#062d2524 65%)}.feature.food:before{background-image:url('https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&w=900&q=80')}.feature.deals:before{background-image:url('https://images.unsplash.com/photo-1601598851547-4302969d0614?auto=format&fit=crop&w=900&q=80')}.feature.services:before{background-image:url('https://images.unsplash.com/photo-1586864387967-d02ef85d93e8?auto=format&fit=crop&w=900&q=80')}.feature.jobs:before{background-image:url('https://images.unsplash.com/photo-1521737711867-e3b97375f902?auto=format&fit=crop&w=900&q=80')}.badge{align-self:flex-start;margin-bottom:auto;background:#ffffffdc;color:var(--pine);padding:6px 8px;border-radius:99px;font-size:10px;font-weight:900}.feature strong{font-size:21px;line-height:1.1}.feature small{color:#eff7f2;margin-top:5px;line-height:1.35}.feed{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.feed article,.result article{background:var(--card);border:1px solid var(--line);padding:17px;border-radius:16px;min-height:165px;display:flex;flex-direction:column;gap:8px;box-shadow:0 8px 18px #092c2605}.feed .tag{font-size:10px;font-weight:900;color:#18704f;background:var(--mint);border-radius:99px;padding:5px 7px;width:max-content}.feed h3,.result h3{margin:0;font-size:16px;line-height:1.2}.feed p,.result p{margin:0;color:var(--muted);font-size:13px;line-height:1.45}.feed a{margin-top:auto;color:var(--orange);font-weight:850;font-size:13px;text-decoration:none}.explore-title{font:43px Georgia,serif;letter-spacing:-1.6px;margin:8px 0 18px}.explore-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.explore-card{min-height:185px;background:#fff;border:1px solid var(--line);border-radius:18px;padding:18px;text-decoration:none;color:var(--ink);display:flex;flex-direction:column;gap:8px;box-shadow:0 8px 18px #092c2605}.explore-card:hover{border-color:#a6c9b8;box-shadow:var(--shadow)}.explore-card span{font-size:25px}.explore-card b{font-size:17px}.explore-card small{color:var(--muted);font-size:13px;line-height:1.4}.explore-card em{font-style:normal;color:var(--orange);font-size:12px;font-weight:850;margin-top:auto}.result{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:15px 0}.empty{padding:18px;border:1px dashed var(--line);border-radius:14px;color:var(--muted);background:#fff}.reward{background:linear-gradient(135deg,#ff6c37,#f3953f);border-radius:23px;color:#fff;padding:32px;max-width:980px}.reward h1{font:60px Georgia,serif;letter-spacing:-2px;margin:8px 0}.reward p{margin:0;color:#fff1e9}.reward-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:11px;margin-top:20px}.reward-stats div{padding:12px;border-radius:12px;background:#ffffff22}.reward-stats b{font-size:18px;display:block}.reward-stats span{font-size:11px;color:#fff5ee}.inbox-tabs{display:flex;gap:8px;margin:15px 0;flex-wrap:wrap}.chip{border:1px solid var(--line);border-radius:99px;background:#fff;padding:9px 13px;color:var(--pine);font-weight:800}.chip.active{background:var(--pine);color:#fff;border-color:var(--pine)}.panel{max-width:980px;background:#fff;border:1px solid var(--line);border-radius:17px;padding:18px}.panel h3{margin:0 0 7px}.panel p{color:var(--muted);line-height:1.5}.profile{max-width:880px}.profile-head{padding:22px;border-radius:19px;background:#fff;border:1px solid var(--line);display:flex;gap:14px;align-items:center}.avatar{height:54px;width:54px;display:grid;place-items:center;border-radius:50%;background:var(--mint);color:#18704f;font-size:22px;font-weight:900}.profile h1{margin:0;font:30px Georgia,serif}.profile p{margin:4px 0 0;color:var(--muted)}.rows{margin-top:14px;border:1px solid var(--line);background:#fff;border-radius:17px;overflow:hidden}.row{padding:16px;display:flex;justify-content:space-between;border-bottom:1px solid var(--line)}.row:last-child{border:0}.row span{color:var(--muted);font-size:12px}.bottom{position:fixed;z-index:5;left:50%;bottom:0;transform:translateX(-50%);display:grid;grid-template-columns:repeat(5,1fr);width:min(1440px,100%);padding:9px 24px calc(9px + env(safe-area-inset-bottom));background:#fffffff0;backdrop-filter:blur(14px);border-top:1px solid var(--line)}.nav{border:0;background:transparent;color:var(--muted);display:grid;gap:4px;justify-items:center;padding:6px;font-size:11px}.nav b{font-size:21px;font-weight:500}.nav.active{color:var(--orange);font-weight:900}@media(max-width:980px){.shell{padding:0 20px 100px}.top{grid-template-columns:auto 1fr}.location{display:none}.feature-grid,.feed,.explore-grid{grid-template-columns:repeat(2,1fr)}.top{gap:16px}}@media(max-width:600px){.shell{padding:0 14px 98px}.top{height:72px;grid-template-columns:auto 1fr;gap:10px}.brand{font-size:21px}.global-search{height:42px;padding-left:10px}.global-search button{padding:0 9px}.hero{padding:28px 22px;min-height:250px}.hero h1{letter-spacing:-1.8px}.feature-grid,.feed,.explore-grid,.result{grid-template-columns:1fr}.feature{min-height:205px}.section{margin-top:29px}.section-head h2{font-size:27px}.explore-title{font-size:34px}.bottom{padding-left:7px;padding-right:7px}.reward h1{font-size:52px}}
</style></head><body><div class="shell"><header class="top"><a class="brand" href="/">balkan<i>.</i>works</a><form class="global-search" id="global-search"><span>⌕</span><input id="global-q" autocomplete="off" placeholder="Pretraži ponude, hranu, usluge, firme…"><button>Traži</button></form><button class="location" id="location-button">⌖ Tvoja lokacija</button></header><main>
<section class="view" id="home"><section class="hero"><div class="eyebrow">Balkan.works · svaki dan</div><h1>Sve lokalno. Jednostavno za korišćenje.</h1><p>Pronađi bolju ponudu, spasi hranu, rezerviši uslugu ili otkrij šta je korisno blizu tebe.</p><div class="hero-actions"><button class="primary" data-view="explore">Istraži Balkan →</button><button class="soft" id="hero-gps">⌖ Uključi lokaciju</button></div></section><section class="section"><div class="section-head"><div><div class="eyebrow">Najčešće</div><h2>Šta ti treba danas?</h2></div></div><div class="feature-grid"><a class="feature food" href="/save-food"><span class="badge">U BLIZINI</span><strong>Save Food</strong><small>Dobri paketi hrane po nižoj ceni.</small></a><a class="feature deals" href="/deals"><span class="badge">AKCIJE</span><strong>Deals</strong><small>Flajeri, kuponi i pametne kupovine.</small></a><a class="feature services" href="/market"><span class="badge">PROVERENO</span><strong>Services</strong><small>Majstori, servisi i lokalna pomoć.</small></a><a class="feature jobs" href="/market"><span class="badge">PRONAĐI POSAO</span><strong>Jobs</strong><small>Lokalni i freelance poslovi.</small></a></div></section><section class="section"><div class="section-head"><div><div class="eyebrow">Personalizovano</div><h2>Za tebe u blizini</h2></div><button data-view="explore">Vidi sve →</button></div><div class="feed" id="home-feed"><div class="empty">Učitavamo lokalne preporuke…</div></div></section></section>
<section class="view" id="explore"><div class="eyebrow">Explore</div><h1 class="explore-title">Svi Balkan.works moduli.</h1><div class="result" id="search-results"></div><div class="explore-grid"><a class="explore-card" href="/save-food"><span>🍎</span><b>Food</b><small>Save Food ponude i rezervacije u blizini.</small><em>Otvori →</em></a><a class="explore-card" href="/deals"><span>🎁</span><b>Deals</b><small>Digitalni flajeri, akcije i kuponi.</small><em>Otvori →</em></a><a class="explore-card" href="/market"><span>🔧</span><b>Services</b><small>Majstori, kućne i servisne usluge.</small><em>Otvori →</em></a><a class="explore-card" href="/market"><span>💼</span><b>Jobs</b><small>Poslovi za lokalne i freelance potrebe.</small><em>Otvori →</em></a><a class="explore-card" href="/business"><span>▦</span><b>Business</b><small>Profil firme, ponude i poslovni alati.</small><em>Otvori →</em></a><button class="explore-card" data-view="profile"><span>⌘</span><b>Money</b><small>Wallet, Rewards i budući finansijski alati.</small><em>Otvori →</em></button><a class="explore-card" href="/everyday"><span>🚗</span><b>Auto</b><small>Gorivo, parking, servisi i podsetnici.</small><em>Otvori →</em></a><a class="explore-card" href="/everyday"><span>🩺</span><b>Health</b><small>Ordinacije, apoteke i termini.</small><em>Otvori →</em></a><button class="explore-card" data-view="inbox"><span>🎟</span><b>Tickets</b><small>Podrška, poruke i zahtevi na jednom mestu.</small><em>Otvori →</em></button><a class="explore-card" href="/local"><span>◎</span><b>Balkan Local</b><small>Događaji, festivali, sajmovi i sport.</small><em>Otvori →</em></a></div></section>
<section class="view" id="rewards"><div class="eyebrow">Balkan Rewards</div><h1 class="explore-title">Tvoja dobra odluka vredi više.</h1><div class="reward"><span class="eyebrow" style="color:#fff3ea">Tvoj Rewards balans</span><h1 id="reward-points">—</h1><p>poena na jednom Balkan ID nalogu</p><div class="reward-stats"><div><b id="reward-tier">—</b><span>Status</span></div><div><b id="reward-impact">—</b><span>Green Score</span></div><div><b id="reward-wallet">—</b><span>Wallet</span></div></div></div></section>
<section class="view" id="inbox"><div class="eyebrow">Inbox</div><h1 class="explore-title">Poruke, podrška i asistencija.</h1><div class="inbox-tabs"><button class="chip active" data-inbox="messages">Poruke</button><button class="chip" data-inbox="notifications">Obaveštenja</button><button class="chip" data-inbox="support">Podrška</button><button class="chip" data-inbox="assistant">AI asistent</button></div><div class="panel" id="inbox-content"><p>Prijavi se da bi koristio/la Inbox.</p></div></section>
<section class="view profile" id="profile"><div class="eyebrow">Balkan ID</div><div class="profile-head"><div class="avatar" id="avatar">B</div><div><h1 id="profile-name">Tvoj Balkan ID</h1><p id="profile-subtitle">Jedan nalog za ceo Balkan.works.</p></div></div><div class="rows"><div class="row"><div><b>Wallet</b><br><span>Saldo i buduća plaćanja</span></div><strong id="profile-wallet">—</strong></div><div class="row"><div><b>Porodica</b><br><span>Rewards i privatna porodična grupa</span></div><a href="/everyday">Otvori →</a></div><div class="row"><div><b>Podešavanja</b><br><span>Jezik, lokacija i privatnost</span></div><a href="/account">Uredi →</a></div></div></section>
</main></div><nav class="bottom"><button class="nav" data-view="home"><b>⌂</b>Home</button><button class="nav" data-view="explore"><b>⌖</b>Explore</button><button class="nav" data-view="rewards"><b>◈</b>Rewards</button><button class="nav" data-view="inbox"><b>◌</b>Inbox</button><button class="nav" data-view="profile"><b>◉</b>Profile</button></nav><script>
const initial='__TAB__',token=()=>localStorage.getItem('balkan_access_token'),auth=()=>token()?{authorization:'Bearer '+token()}:{};const $=id=>document.getElementById(id);const esc=v=>String(v??'').replace(/[&<>"']/g,x=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[x]));const money=(n,c='EUR')=>n==null?'Dogovor':Number(n).toLocaleString('sr-RS',{style:'currency',currency:c});async function api(url,opt={}){const r=await fetch(url,{...opt,headers:{...auth(),...(opt.headers||{})}}),d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(d.detail||'Zahtev nije uspeo.');return d}function view(name){document.querySelectorAll('.view').forEach(x=>x.classList.toggle('active',x.id===name));document.querySelectorAll('.nav').forEach(x=>x.classList.toggle('active',x.dataset.view===name));if(name==='home')home();if(name==='rewards')rewards();if(name==='inbox')inbox('messages');if(name==='profile')profile();scrollTo({top:0,behavior:'smooth'})}document.querySelectorAll('[data-view]').forEach(x=>x.onclick=()=>view(x.dataset.view));
async function home(){const city=localStorage.getItem('balkan_city')||'',q=city?'?city_name='+encodeURIComponent(city):'';try{const [offers,food,market]=await Promise.all([api('/api/deals/offers'+q),api('/api/food/packages'),api('/api/market/listings'+q)]);const items=[...offers.slice(0,2).map(x=>['DEALS',x.title,(x.city_name||x.country_code)+' · '+money(x.price,x.currency),'/deals']),...food.slice(0,1).map(x=>['SAVE FOOD',x.title,'Preuzimanje · '+money(x.price,x.currency),'/save-food']),...market.slice(0,1).map(x=>[x.listing_type,x.title,(x.city_name||x.country_code)+' · '+money(x.price,x.currency),'/market'])];$('home-feed').innerHTML=items.length?items.map(x=>'<article><span class="tag">'+esc(x[0])+'</span><h3>'+esc(x[1])+'</h3><p>'+esc(x[2])+'</p><a href="'+x[3]+'">Pogledaj →</a></article>').join(''):'<div class="empty">Još nema objava u blizini. Izaberi grad ili istraži module.</div>'}catch(e){$('home-feed').innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}
async function search(q){if(!q.trim())return;view('explore');$('search-results').innerHTML='<div class="empty">Pretražujemo ceo Balkan.works…</div>';try{const data=await api('/api/search?q='+encodeURIComponent(q)),values=Object.values(data).flat().slice(0,12);$('search-results').innerHTML=values.length?values.map(x=>'<article><h3>'+esc(x.title||x.name||'Rezultat')+'</h3><p>'+esc(x.description||x.city_name||x.type||'Balkan.works')+'</p></article>').join(''):'<div class="empty">Nema rezultata. Probaj drugi pojam ili grad.</div>'}catch(e){$('search-results').innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}$('global-search').onsubmit=e=>{e.preventDefault();search($('global-q').value)};
$('hero-gps').onclick=()=>navigator.geolocation&&navigator.geolocation.getCurrentPosition(p=>{localStorage.setItem('balkan_lat',p.coords.latitude);localStorage.setItem('balkan_lng',p.coords.longitude);$('location-button').textContent='✓ Lokacija uključena';home()});$('location-button').onclick=()=>$('hero-gps').click();
async function rewards(){if(!token())return;try{const [hub,green]=await Promise.all([api('/api/super-app/hub'),api('/api/life/green-score')]);$('reward-points').textContent=hub.rewards.points;$('reward-tier').textContent=hub.rewards.tier;$('reward-wallet').textContent=money(hub.wallet.balance,hub.wallet.currency);$('reward-impact').textContent=green.food_packages_rescued+' paketa'}catch(e){$('reward-points').textContent='—'}}
async function inbox(kind){document.querySelectorAll('[data-inbox]').forEach(x=>x.classList.toggle('active',x.dataset.inbox===kind));if(!token()){$('inbox-content').innerHTML='<p>Prijavi se da vidiš poruke, podršku i Balkan Assistant.</p>';return}if(kind==='assistant'){$('inbox-content').innerHTML='<h3>Balkan Assistant</h3><p>Bezbedni AI pristup se aktivira nakon povezivanja OpenAI ključa. Tada će asistent pretraživati samo Balkan.works module.</p>';return}try{const url=kind==='messages'?'/api/market/messages':kind==='notifications'?'/api/notifications':'/api/support/tickets',rows=await api(url);$('inbox-content').innerHTML=rows.length?rows.map(x=>'<article><h3>'+esc(x.title||x.subject||'Poruka')+'</h3><p>'+esc(x.body||x.detail||'Nova aktivnost.')+'</p></article>').join(''):'<p>Nema novih stavki u ovom delu Inbox-a.</p>'}catch(e){$('inbox-content').innerHTML='<p>'+esc(e.message)+'</p>'}}document.querySelectorAll('[data-inbox]').forEach(x=>x.onclick=()=>inbox(x.dataset.inbox));
async function profile(){if(!token()){ $('profile-name').textContent='Tvoj Balkan ID';$('profile-subtitle').textContent='Prijavi se jednim nalogom za ceo Balkan.works.';return}try{const [me,wallet]=await Promise.all([api('/api/me'),api('/api/payments/wallet')]);$('profile-name').textContent=me.profile.display_name;$('profile-subtitle').textContent=me.user.email+' · '+(me.profile.city_name||'Podesi lokaciju');$('avatar').textContent=(me.profile.display_name||'B')[0].toUpperCase();$('profile-wallet').textContent=money(wallet.balance,wallet.currency)}catch(e){$('profile-subtitle').textContent=e.message}}
view(initial);
</script></body></html>'''.replace("__LANG__", language).replace("__TAB__", tab)
